function e(e){if(!e)return``;let t=Date.now()-new Date(e).getTime(),n=Math.floor(t/6e4);if(n<1)return`только что`;if(n<60)return`${n} мин. назад`;let r=Math.floor(n/60);return r<24?`${r} ч. назад`:`${Math.floor(r/24)} дн. назад`}function t(e){if(!e)return``;let t=Date.now()-new Date(e).getTime(),n=Math.floor(t/6e4);if(n<1)return`сейчас`;if(n<60)return`${n} мин.`;let r=Math.floor(n/60);if(r<24)return`${r} ч.`;let i=Math.floor(r/24);return i===1?`вчера`:`${i} дн.`}function n(e,t=!1){if(t)return`в сети`;if(!e)return``;let n=new Date(e),r=Date.now()-n.getTime(),i=Math.floor(r/6e4);if(i<1)return`был только что`;if(i<60)return`был ${i} мин назад`;let a=Math.floor(i/60);if(a<24)return`был ${a} ч назад`;let o=Math.floor(a/24);return o===1?`был вчера в ${String(n.getHours()).padStart(2,`0`)}:${String(n.getMinutes()).padStart(2,`0`)}`:o<7?`был ${o} дн назад`:`был ${n.toLocaleDateString(`ru-RU`)}`}export{e as n,t as r,n as t};